123	/// Creates a new scope for spawning threads.
124	///
125	/// All child threads that haven't been manually joined will be automatically joined just before
126	/// this function invocation ends. If all joined threads have successfully completed, `Ok` is
127	/// returned with the return value of `f`. If any of the joined threads has panicked, an `Err` is
128	/// returned containing errors from panicked threads. Note that if panics are implemented by
129	/// aborting the process, no error is returned; see the notes of [std::panic::catch_unwind].
130	///
131	/// **Note:** Since Rust 1.63, this function is soft-deprecated in favor of the more efficient [`std::thread::scope`].
132	///
133	/// # Examples
134	///
135	/// ```
136	/// use crossbeam_utils::thread;
137	///
138	/// let var = vec![1, 2, 3];
139	///
140	/// thread::scope(|s| {
141	///     s.spawn(|_| {
142	///         println!("A child thread borrowing `var`: {:?}", var);
143	///     });
144	/// }).unwrap();
145	/// ```
146	pub fn scope<'env, F, R>(f: F) -> thread::Result<R>
147	where
148	    F: FnOnce(&Scope<'env>) -> R,
149	{
150	    struct AbortOnPanic;
151	    impl Drop for AbortOnPanic {
152	        fn drop(&mut self) {
153	            if thread::panicking() {
154	                std::process::abort();
155	            }
156	        }
157	    }
158	
159	    let wg = WaitGroup::new();
160	    let scope = Scope::<'env> {
161	        handles: SharedVec::default(),
162	        wait_group: wg.clone(),
163	        _marker: PhantomData,
164	    };
165	
166	    // Execute the scoped function, but catch any panics.
167	    let result = panic::catch_unwind(panic::AssertUnwindSafe(|| f(&scope)));
168	
169	    // If an unwinding panic occurs before all threads are joined
170	    // promote it to an aborting panic to prevent any threads from escaping the scope.
171	    let guard = AbortOnPanic;
172	
173	    // Wait until all nested scopes are dropped.
174	    drop(scope.wait_group);
175	    wg.wait();
176	
177	    // Join all remaining spawned threads.
178	    let panics: Vec<_> = scope
179	        .handles
180	        .lock()
181	        .unwrap()
182	        // Filter handles that haven't been joined, join them, and collect errors.
183	        .drain(..)
184	        .filter_map(|handle| handle.lock().unwrap().take())
185	        .filter_map(|handle| handle.join().err())
186	        .collect();
187	
188	    mem::forget(guard);
189	
190	    // If `f` has panicked, resume unwinding.
191	    // If any of the child threads have panicked, return the panic errors.
192	    // Otherwise, everything is OK and return the result of `f`.
193	    match result {
194	        Err(err) => panic::resume_unwind(err),
195	        Ok(res) => {
196	            if panics.is_empty() {
197	                Ok(res)
198	            } else {
199	                Err(Box::new(panics))
200	            }
201	        }
202	    }
203	}
