486	/// A handle that can be used to join its scoped thread.
487	///
488	/// This struct is created by the [`Scope::spawn`] method and the
489	/// [`ScopedThreadBuilder::spawn`] method.
490	pub struct ScopedJoinHandle<'scope, T> {
491	    /// A join handle to the spawned thread.
492	    handle: SharedOption<thread::JoinHandle<()>>,
493	
494	    /// Holds the result of the inner closure.
495	    result: SharedOption<T>,
496	
497	    /// A handle to the spawned thread.
498	    thread: thread::Thread,
499	
500	    /// Borrows the parent scope with lifetime `'scope`.
501	    _marker: PhantomData<&'scope ()>,
502	}
503	
504	impl<T> ScopedJoinHandle<'_, T> {
505	    /// Waits for the thread to finish and returns its result.
506	    ///
507	    /// If the child thread panics, an error is returned. Note that if panics are implemented by
508	    /// aborting the process, no error is returned; see the notes of [std::panic::catch_unwind].
509	    ///
510	    /// # Panics
511	    ///
512	    /// This function may panic on some platforms if a thread attempts to join itself or otherwise
513	    /// may create a deadlock with joining threads.
514	    ///
515	    /// # Examples
516	    ///
517	    /// ```
518	    /// use crossbeam_utils::thread;
519	    ///
520	    /// thread::scope(|s| {
521	    ///     let handle1 = s.spawn(|_| println!("I'm a happy thread :)"));
522	    ///     let handle2 = s.spawn(|_| panic!("I'm a sad thread :("));
523	    ///
524	    ///     // Join the first thread and verify that it succeeded.
525	    ///     let res = handle1.join();
526	    ///     assert!(res.is_ok());
527	    ///
528	    ///     // Join the second thread and verify that it panicked.
529	    ///     let res = handle2.join();
530	    ///     assert!(res.is_err());
531	    /// }).unwrap();
532	    /// ```
533	    pub fn join(self) -> thread::Result<T> {
534	        // Take out the handle. The handle will surely be available because the root scope waits
535	        // for nested scopes before joining remaining threads.
536	        let handle = self.handle.lock().unwrap().take().unwrap();
537	
538	        // Join the thread and then take the result out of its inner closure.
539	        handle
540	            .join()
541	            .map(|()| self.result.lock().unwrap().take().unwrap())
542	    }
543	
544	    /// Returns a handle to the underlying thread.
545	    ///
546	    /// # Examples
547	    ///
548	    /// ```
549	    /// use crossbeam_utils::thread;
550	    ///
551	    /// thread::scope(|s| {
552	    ///     let handle = s.spawn(|_| println!("A child thread is running"));
553	    ///     println!("The child thread ID: {:?}", handle.thread().id());
554	    /// }).unwrap();
555	    /// ```
556	    pub fn thread(&self) -> &thread::Thread {
557	        &self.thread
558	    }
559	}
560	
561	/// Unix-specific extensions.
562	#[cfg(unix)]
563	pub mod unix {
564	    use std::os::unix::thread::JoinHandleExt as _;
565	    #[doc(no_inline)]
566	    pub use std::os::unix::thread::RawPthread;
567	
568	    use super::ScopedJoinHandle;
569	
570	    mod sealed {
571	        pub trait Sealed {}
572	    }
573	
574	    /// Unix-specific extensions to [`ScopedJoinHandle`].
575	    pub trait JoinHandleExt: sealed::Sealed {
576	        /// Extracts the raw pthread_t without taking ownership
577	        fn as_pthread_t(&self) -> RawPthread;
578	
579	        /// Consumes the thread, returning the raw pthread_t
580	        ///
581	        /// This function **transfers ownership** of the underlying pthread_t to
582	        /// the caller. Callers are then the unique owners of the pthread_t and
583	        /// must either detach or join the pthread_t once it's no longer needed.
584	        fn into_pthread_t(self) -> RawPthread;
585	    }
586	
587	    impl<T> sealed::Sealed for ScopedJoinHandle<'_, T> {}
588	    impl<T> JoinHandleExt for ScopedJoinHandle<'_, T> {
589	        fn as_pthread_t(&self) -> RawPthread {
590	            // Borrow the handle. The handle will surely be available because the root scope waits
591	            // for nested scopes before joining remaining threads.
592	            let handle = self.handle.lock().unwrap();
593	            handle.as_ref().unwrap().as_pthread_t()
594	        }
595	        fn into_pthread_t(self) -> RawPthread {
596	            self.as_pthread_t()
597	        }
598	    }
599	}
600	/// Windows-specific extensions.
601	#[cfg(windows)]
602	mod windows {
603	    use std::os::windows::io::{AsRawHandle, IntoRawHandle, RawHandle};
604	
605	    use super::ScopedJoinHandle;
606	
607	    impl<T> AsRawHandle for ScopedJoinHandle<'_, T> {
608	        fn as_raw_handle(&self) -> RawHandle {
609	            // Borrow the handle. The handle will surely be available because the root scope waits
610	            // for nested scopes before joining remaining threads.
611	            let handle = self.handle.lock().unwrap();
612	            handle.as_ref().unwrap().as_raw_handle()
613	        }
614	    }
615	
616	    impl<T> IntoRawHandle for ScopedJoinHandle<'_, T> {
617	        fn into_raw_handle(self) -> RawHandle {
618	            self.as_raw_handle()
619	        }
620	    }
621	}
